local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxHeroBookCtrl:LxBaseCtrl
local LxHeroBookCtrl = classX("LxHeroBookCtrl", LxBaseCtrl)

function LxHeroBookCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
    self:InitHeroBookRef()
end

function LxHeroBookCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxHeroBookCtrl:InitHeroBookRef()
    local qualityHeroBookMap = {}
    for k,v in pairs(GameTable.HeroBookRef) do
        local qualityHeroBooks = qualityHeroBookMap[v.quality]
        if not qualityHeroBooks then
            qualityHeroBooks = {}
            qualityHeroBookMap[v.quality] = qualityHeroBooks
        end
        table.insert(qualityHeroBooks,{
            refId = k,
            level = v.level,
            needHeroStar = v.needHeroStar,
            quality = v.quality,
        })
    end
    for k,v in pairs(qualityHeroBookMap) do
        table.sort(v,function(a,b) return a.level < b.level end)
    end
    self._qualityHeroBookMap = qualityHeroBookMap
end

function LxHeroBookCtrl:GetQualityHeroBooks(quality)
    if not self._qualityHeroBookMap then
        self:InitHeroBookRef()
    end
    return self._qualityHeroBookMap[quality]
end

---@return V_HeroBookRef
function LxHeroBookCtrl:GetQualityFirstHeroBookRef(quality)
    local qualityHeroBooks = self:GetQualityHeroBooks(quality)
    if not qualityHeroBooks or #qualityHeroBooks < 0 then return end
    local first = qualityHeroBooks[1]
    return self:GetHeroBookRef(first.refId)
end

function LxHeroBookCtrl:GetHeroBookRef(refId)
    return GameTable.HeroBookRef[refId]
end

---@param curRef V_HeroBookRef
function LxHeroBookCtrl:GetNextUpLevelRef(curRef)
    if not curRef then return end

    local nextRefId = curRef.refId + 1
    return self:GetHeroBookRef(nextRefId)
end

---@param curRef V_HeroBookRef
function LxHeroBookCtrl:CheckIsFullMaxLevel(curRef)
    local nextRef = self:GetNextUpLevelRef(curRef)
    return nextRef == nil
end

function LxHeroBookCtrl:GetBookHeroList(params)
    params = params or {}

    local raceType = params.raceType or 0
    local careerType = params.careerType or 0
    local attackType = params.attackType or 0
    local heroBookData
    local quality = 0
    local qualityHeroMap = {}
    for k,v in pairs(GameTable.CharacterRef) do
        local isIns = false
        if raceType == 0 or v.raceType == raceType then
            if careerType == 0 or v.careerType == careerType then
                if attackType == 0 or v.actType == attackType then
                    isIns = true
                end
            end
        end
        if isIns then
            quality = v.quality
            local qualityHeros = qualityHeroMap[quality]
            if not qualityHeros then
                qualityHeros = {}
                qualityHeroMap[quality] = qualityHeros
            end
            heroBookData = self:GetHeroBookData(k)
            if heroBookData then
                table.insert(qualityHeros,heroBookData)
            end
        end
    end

    local resultList = {}
    for k,qualityHeros in pairs(qualityHeroMap) do
        table.sort(qualityHeros,function(a,b)
            return a.order < b.order
        end)
        table.insert(resultList,{
            quality = k,
            qualityHeros = qualityHeros,
        })
    end
    table.sort(resultList,function(a,b)
        return a.quality > b.quality
    end)

    local index
    local newResultList = {}
    for i,v in ipairs(resultList) do
        table.insert(newResultList,{
            showQuality = true,
            quality = v.quality,
        })
        local qualityHeros = v.qualityHeros
        local line = math.ceil(#qualityHeros / 4)
        for lIdx = 1,line do
            local tqualityHeros = {}
            for idx = 1,4 do
                index = (lIdx - 1) * 4 + idx
                if not qualityHeros[index] then break end
                table.insert(tqualityHeros,qualityHeros[index])
            end
            table.insert(newResultList,{
                showHero = true,
                qualityHeros = tqualityHeros,
            })
        end
    end

    return newResultList
end


function LxHeroBookCtrl:GetBookHeroCanOptList(params)
    params = params or {}
    local raceType = params.raceType or 0
    local careerType = params.careerType or 0
    local attackType = params.attackType or 0
    local curQualityData = params.curQualityData
    local maskRefId = curQualityData and curQualityData.refId

    local heroBookData,state
    local resultList = {}
    for k,v in pairs(GameTable.CharacterRef) do
        if not maskRefId or maskRefId ~= k then
            local isIns = false
            if raceType == 0 or v.raceType == raceType then
                if careerType == 0 or v.careerType == careerType then
                    if attackType == 0 or v.actType == attackType then
                        isIns = true
                    end
                end
            end
            if isIns then
                heroBookData = self:GetHeroBookData(k)
                state = heroBookData and heroBookData.state
                if state and (state == HeroBookOptEnum.UpLevel or state == HeroBookOptEnum.Act) then
                    table.insert(resultList,heroBookData)
                end
            end
        end
    end
    return resultList
end


--- 涉及修改的函数 CheckSingleHeroBookRP（单纯计算红点）
function LxHeroBookCtrl:GetHeroBookData(heroRefId)
    local heroRef = LxDataHelper.GetHeroRef(heroRefId)
    if not heroRef then return end

    ---@type V_HeroBookRef 升级显示
    local nextHeroBookRef
    local isMaxLv = false
    local quality = heroRef.quality
    local state = HeroBookOptEnum.NoDefine
    local heroBookInfo = ModuleCenter.HeroBook:GetHeroBookInfo(heroRefId)
    local notGetState = heroBookInfo == nil
    if heroBookInfo and heroBookInfo:IsBookAct() then
        local heroBookRefId = heroBookInfo.refId

        ---@type V_HeroBookRef
        local heroBookRef = self:GetHeroBookRef(heroBookRefId)
        if not heroBookRef then return end

        isMaxLv = self:CheckIsFullMaxLevel(heroBookRef)
        if isMaxLv then
            state = HeroBookOptEnum.FullLevel
        else
            local tHeroBookRefId = LxDataHelper.GetHeroBookRefId(quality,heroBookRef.level)
            nextHeroBookRef = self:GetHeroBookRef(tHeroBookRefId)
            if nextHeroBookRef then
                local maxStar = heroBookInfo.maxStar
--[[                --- 服务端记录最大等级，所以下面代码注释
                local heroList = ModuleCenter.Hero:GetRefHeroList(heroRefId)
                if heroList and #heroList > 0 then
                    table.sort(heroList,function(a,b) return a.maxStar > b.maxStar end)
                    if heroList[1].maxStar > maxStar then
                        maxStar = heroList[1].maxStar
                    end
                end]]
                if maxStar >= nextHeroBookRef.needHeroStar then
                    state = HeroBookOptEnum.UpLevel
                else
                    state = HeroBookOptEnum.NoUpLevel
                end
            else
                state = HeroBookOptEnum.FullLevel
            end
        end
    else
        local heroBookRefId = LxDataHelper.GetHeroBookRefId(quality,0)
        local heroBookRef = self:GetHeroBookRef(heroBookRefId)
        if not heroBookRef then return end

        nextHeroBookRef = heroBookRef

        state = HeroBookOptEnum.NoAct

        if heroBookInfo and heroBookInfo.maxStar >= heroBookRef.needHeroStar then
            state = HeroBookOptEnum.Act
        end

--[[        local heroList = ModuleCenter.Hero:GetRefHeroList(heroRefId)
        if heroList and #heroList > 0 then
            table.sort(heroList,function(a,b) return a.maxStar > b.maxStar end)
            if heroList[1].maxStar > heroBookRef.needHeroStar then
                state = HeroBookOptEnum.Act
            end
        end]]
    end

    local isShowRed = state == HeroBookOptEnum.Act or state == HeroBookOptEnum.UpLevel
    return {
        refId = heroRefId,
        order = heroRef.order,
        quality = quality,
        heroBookInfo = heroBookInfo,
        notGetState = notGetState,
        state = state,
        heroRef = heroRef,
        showStar = heroRef.initStar,
        raceType = heroRef.raceType,
        careerType = heroRef.careerType,
        isMaxLv = isMaxLv,
        nextHeroBookRef = nextHeroBookRef,
        isShowRed = isShowRed,
    }
end

