function LxHeroBookCtrl:GetBookHeroTrainAttrList(qualityData)
    local cAttrMap = {}
    local nAttrMap = {}
    local isMax = false

    local quality = qualityData.quality
    if qualityData.notGetState then
        local firstData = self:GetQualityFirstHeroBookRef(quality)
        if firstData then
            local nAttrList = self:GetHeroBookAttrList(firstData)
            self:_DisposeAttrMap(nAttrList,nAttrMap)
        end
    else
        ---@type LxHeroBookInfo
        local heroBookInfo = qualityData.heroBookInfo
        if heroBookInfo then
            if heroBookInfo:IsBookAct() then
                local curRef = self:GetHeroBookRef(heroBookInfo.refId)
                if curRef then
                    local cAttrList = self:GetHeroBookAttrList(curRef)
                    self:_DisposeAttrMap(cAttrList,cAttrMap)
                    local nextRef = self:GetNextUpLevelRef(curRef)
                    isMax = nextRef == nil
                    if nextRef then
                        ---@return V_Attr[]
                        local nAttrList = self:GetHeroBookAttrList(nextRef)
                        self:_DisposeAttrMap(nAttrList,nAttrMap)
                    end
                end
            else
                local heroBookRefId = LxDataHelper.GetHeroBookRefId(quality,0)
                local curRef = self:GetHeroBookRef(heroBookRefId)
                if curRef then
                    ---@return V_Attr[]
                    local nAttrList = self:GetHeroBookAttrList(curRef)
                    self:_DisposeAttrMap(nAttrList,nAttrMap)
                end
            end
        end
    end
    local list = {}
    if isMax then
        for attrRefId,tarMap in pairs(cAttrMap) do
            for tar,attrData in pairs(tarMap) do
                table.insert(list,{
                    refId = attrRefId,
                    bValue = attrData.value,
                    nValue = -1,
                    isMax = true,
                })
            end
        end
    else
        for attrRefId,tarMap in pairs(nAttrMap) do
            for tar,attrData in pairs(tarMap) do
                local bTarMap = cAttrMap[attrRefId]
                local bAttrValue = 0
                if bTarMap and bTarMap[tar] then
                    bAttrValue = bTarMap[tar].value
                end
                table.insert(list,{
                    refId = attrRefId,
                    bValue = bAttrValue,
                    nValue = attrData.value,
                    isMax = false,
                })
            end
        end
    end
    table.sort(list,function(a,b)
        return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
    end)
    return list
end

---@param attrList V_Attr[]
function LxHeroBookCtrl:_DisposeAttrMap(attrList,attrMap)
    local refId,tar
    for i,v in ipairs(attrList) do
        refId = v.refId
        local bRecord = attrMap[refId]
        if not bRecord then
            bRecord = {}
            attrMap[refId] = bRecord
        end

        tar = v.tar
        local bTarRecord = bRecord[tar]
        if not bTarRecord then
            bTarRecord = {
                refId = refId,
                value = 0,
                tar = tar
            }
            bRecord[tar] = bTarRecord
        end
        bTarRecord.value = bTarRecord.value + v.value
    end
end

--- 打开英雄图鉴属性界面
function LxHeroBookCtrl:OpenBookHeroAttrPreview()
    local attrNum = 0
    local attrMap = {}
    local ref

    ---@type V_Attr[]
    local attrs
    local heroBookMap = ModuleCenter.HeroBook:GetHeroBookInfoMap()
    for k,v in pairs(heroBookMap) do
        if v.refId and v.refId > 0 then
            ref = self:GetHeroBookRef(v.refId)
            attrs = self:GetHeroBookAttrList(ref)
            if #attrs > 0 then
                for idx,val in ipairs(attrs) do
                    local attrTarMap = attrMap[val.refId]
                    if not attrTarMap then
                        attrTarMap = {}
                        attrMap[val.refId] = attrTarMap
                    end
                    local value = attrTarMap[val.tar] or 0
                    attrTarMap[val.tar] = value + val.value
                end
                attrNum = attrNum + 1
            end
        end
    end
    local resultList = {}
    if attrNum > 0 then
        for refId,tarMap in pairs(attrMap) do
            for tar,value in pairs(tarMap) do
                table.insert(resultList,{
                    refId = refId,
                    value = value,
                    tar = tar,
                })
            end
        end
        table.sort(resultList,function(a,b)
            return LxDataHelper.GetCombatAttributeSort(a.refId) < LxDataHelper.GetCombatAttributeSort(b.refId)
        end)
    else
        local heroBookAttrShow = GameTable.CharacterConfigRef["heroBookAttrShow"]
        if heroBookAttrShow and #heroBookAttrShow > 0 then
            for i,v in ipairs(heroBookAttrShow) do
                table.insert(resultList,{
                    refId = v,
                    value = 0,
                    tar = 0,
                })
            end
        end
    end
    ShowPanel(UiNames.HeroBookAttrPreview,{
        attrList = resultList
    })
end

