function LxHeroBookCtrl:GetHeroAudioInfo(heroRefId)
    if not self._heroAudioInfoMap then
        self._heroAudioInfoMap = {}
    end
    local heroAudioInfo = self._heroAudioInfoMap[heroRefId]
    if not heroAudioInfo then
        local effRef = LxDataHelper.GetHeroEffectRef(heroRefId)
        if effRef then
            heroAudioInfo = {}

            local sortIndex = 1
            --- 英雄台词文本 + 英雄台词音频文件
            local audioType = HeroAudioEnum.Dialogue
            local dialogueInfo = {}
            local lineText = string.split(I18nText(effRef.lineText),"|")
            local lineAudio = effRef.lineAudio
            for i,v in ipairs(lineAudio) do
                table.insert(dialogueInfo,{
                    dialogueTxt = lineText[i],
                    dialogueAudio = v,
                })
            end
            heroAudioInfo[audioType] = {
                btnName = I18nText(8034),
                btnData = dialogueInfo,
                audioType = audioType,
                sortIndex = sortIndex,
            }

            --- 战斗语音文本 + 战斗语音
            local fightInfoMap = {}
            local fightTextMap = {}
            local fightText = string.split(I18nText(effRef.fightText),"|")
            for i,v in ipairs(fightText) do
                v = string.split(v,"=")
                fightTextMap[v[1]] = v[2]
            end
            local key
            local fightAudio = string.split(effRef.fightAudio,"|")
            for i,v in ipairs(fightAudio) do
                v = string.split(v,"=")
                key = v[1]
                fightInfoMap[key] = {
                    dialogueTxt = fightTextMap[key],
                    dialogueAudio = v[2],
                }
            end
            for i,v in ipairs(HeroFightAudioEnum) do
                audioType = v.audioType
                if fightInfoMap[audioType] then
                    sortIndex = sortIndex + 1
                    heroAudioInfo[audioType] = {
                        btnName = v.btnName,
                        btnData = {
                            fightInfoMap[audioType]
                        },
                        audioType = audioType,
                        sortIndex = sortIndex,
                    }
                end
            end

            --- 升星语音文本 + 升星语音
            local upStarAudio = effRef.upStarAudio
            if upStarAudio and #upStarAudio > 0 then
                audioType = HeroAudioEnum.UpStar
                sortIndex = sortIndex + 1
                local info = self:CommonDisposeAudioAndText(upStarAudio,effRef.upStarText)
                heroAudioInfo[audioType] = {
                    btnName = I18nText(8038),
                    btnData = info,
                    audioType = audioType,
                    sortIndex = sortIndex,
                }
            end


            --- 召唤语音文本 + 召唤语音
            local callAudio = effRef.callAudio
            if callAudio and #callAudio > 0 then
                audioType = HeroAudioEnum.HeroCall
                sortIndex = sortIndex + 1
                local info = self:CommonDisposeAudioAndText(callAudio,effRef.callText)
                heroAudioInfo[audioType] = {
                    btnName = I18nText(8039),
                    btnData = info,
                    audioType = audioType,
                    sortIndex = sortIndex,
                }
            end

            --- 胜利语音文本 + 胜利语音
            local winAudio = effRef.winAudio
            if winAudio and #winAudio > 0 then
                audioType = HeroAudioEnum.Win
                sortIndex = sortIndex + 1
                local info = self:CommonDisposeAudioAndText(winAudio,effRef.winText)
                heroAudioInfo[audioType] = {
                    btnName = I18nText(8040),
                    btnData = info,
                    audioType = audioType,
                    sortIndex = sortIndex,
                }
            end

            --- 失败语音文本 + 失败语音
            local loseAudio = effRef.loseAudio
            if loseAudio and #loseAudio > 0 then
                audioType = HeroAudioEnum.Lose
                sortIndex = sortIndex + 1
                local info = self:CommonDisposeAudioAndText(loseAudio,effRef.loseText)
                heroAudioInfo[audioType] = {
                    btnName = I18nText(8041),
                    btnData = info,
                    audioType = audioType,
                    sortIndex = sortIndex,
                }
            end

            self._heroAudioInfoMap[heroRefId] = heroAudioInfo
        end
    end
    return heroAudioInfo
end

function LxHeroBookCtrl:CommonDisposeAudioAndText(audioList,text)
    local info = {}
    local textStr = I18nText(text)
    local textStrList = string.split(textStr,"|")
    for i,v in ipairs(audioList) do
        table.insert(info,{
            dialogueTxt = textStrList[i],
            dialogueAudio = v,
        })
    end
    return info
end

function LxHeroBookCtrl:GetHeroAudioList(heroRefId)
    if not self._heroAudioList then
        self._heroAudioList = {}
    end
    local tempList = self._heroAudioList[heroRefId]
    if not tempList then
        tempList = {}

        local heroAudioInfo = self:GetHeroAudioInfo(heroRefId)
        if heroAudioInfo then
            for k,v in pairs(heroAudioInfo) do
                table.insert(tempList,v)
            end
            table.sort(tempList,function(a,b)
                return a.sortIndex < b.sortIndex
            end)
        end
    end
    return tempList
end


function LxHeroBookCtrl:GetHeroStoryInfo(heroRefId,loveLevel)
    if not self._heroStoryInfoMap then
        self._heroStoryInfoMap = {}
    end
    local heroStoryInfo = self._heroStoryInfoMap[heroRefId]
    if not heroStoryInfo then
        heroStoryInfo = {}
        for k,v in pairs(GameTable.CharacterStoryRef) do
            if v.group == heroRefId then
                table.insert(heroStoryInfo,{
                    refId = k,
                    group = heroRefId,
                    name = I18nText(v.name),
                    dec = I18nText(v.dec),
                    needStart = v.needStart,
                })
            end
        end
        table.sort(heroStoryInfo,function(a,b)
            return a.refId < b.refId
        end)
        self._heroStoryInfoMap[heroRefId] = heroStoryInfo
    end
    loveLevel = loveLevel or 0
    local list = {}
    for i,v in ipairs(heroStoryInfo) do
        table.insert(list,{
            ref = v,
            unlock = loveLevel >= v.needStart,
        })
    end
    return list
end


