end



--- 涉及修改的函数 GetHeroBookData（获取数据，界面使用）
---@param heroRefId number 获取英雄图鉴的红点
function LxHeroBookCtrl:CheckSingleHeroBookRP(heroRefId)
    if not heroRefId or heroRefId < 1 then return false end

    local heroRef = LxDataHelper.GetHeroRef(heroRefId)
    if not heroRef then return false end

    ---@type LxHeroBookInfo
    local heroBookInfo = ModuleCenter.HeroBook:GetHeroBookInfo(heroRefId)
    if not heroBookInfo then return false end

    if heroBookInfo:IsBookAct() then
        ---@type V_HeroBookRef
        local heroBookRef = self:GetHeroBookRef(heroBookInfo.refId)
        if not heroBookRef then return false end
        if self:CheckIsFullMaxLevel(heroBookRef) then return false end
        local nextHBRefId = LxDataHelper.GetHeroBookRefId(heroRef.quality,heroBookRef.level)
        local nextHBRef = self:GetHeroBookRef(nextHBRefId)
        if nextHBRef then
            local maxStar = heroBookInfo.maxStar
            if maxStar >= nextHBRef.needHeroStar then
                return true
            end
        end
    else
        local heroBookRefId = LxDataHelper.GetHeroBookRefId(heroRef.quality,0)
        local heroBookRef = self:GetHeroBookRef(heroBookRefId)
        if heroBookRef then
            if heroBookInfo.maxStar >= heroBookRef.needHeroStar then
                return true
            end
        end
    end
    return false
end


--- params:拓展用
--- 图鉴按钮入口，包括 英雄图鉴，皮肤图鉴
function LxHeroBookCtrl:CheckHeroBookEnterRP(params)
    if self:CheckHeroBookRP(params) then
        return true
    end
    if CtrlCenter.HeroSkin:CheckSkinBookRP() then
        return true
    end
end


--- 打开通用的英雄满级满星界面 预览
function LxHeroBookCtrl:OpenPreviewHeroMax(heroRefId)
    --- 打开皮肤界面
    local openUIParams = {}
    table.insert(openUIParams,{
        uiName = UiNames.HeroFavorabilityAttr,
        btnName = I18nText(2508),
        btnType = 1,
        uiParams = {
            heroRefId = heroRefId,
            openView = 2,
        }
    })
    ShowPanel(UiNames.HeroOptMain,{
        openUIParams = openUIParams,
    })
end

function LxHeroBookCtrl:GetHeroNoteRefsByRefId(heroRefId)
    if not self._heroNoteRefMap then
        self._heroNoteRefMap = {}
    end
    local heroNoteRefs = self._heroNoteRefMap[heroRefId]
    if not heroNoteRefs then
        heroNoteRefs = {}
        for k,v in pairs(GameTable.HeroNoteRef) do
            if v.hero == heroRefId then
                table.insert(heroNoteRefs,v)
            end
        end
        self._heroNoteRefMap[heroRefId] = heroNoteRefs
    end
    return heroNoteRefs
end

function LxHeroBookCtrl:GetHeroCommentBarrageStatus()
    local status = checknumber(LxPlayerPrefs.HeroCommentBarrage)
    if status == -1 then
        local heroNoteshow = GameTable.CharacterConfigRef.heroNoteshow
        status = checknumber(heroNoteshow)
        self:SetHeroCommentBarrageStatus(status == 1)
    end
    return status == 1
end

function LxHeroBookCtrl:SetHeroCommentBarrageStatus(status)
    local val = status and 1 or 0
    LxPlayerPrefs.HeroCommentBarrage = tostring(val)
end


return LxHeroBookCtrl